import{_ as t,o as i,c as s,ag as o}from"./chunks/framework.DUvHsH_U.js";const d=JSON.parse('{"title":"Initial App Launch and Settings Access Setup","description":"","frontmatter":{"prev":false,"next":{"text":"Login","link":"/getting-started/login-setup.html"}},"headers":[],"relativePath":"getting-started/initial-api-authentication-setup.md","filePath":"getting-started/initial-api-authentication-setup.md","lastUpdated":1777977250000}'),n={name:"getting-started/initial-api-authentication-setup.md"};function r(l,e,a,g,c,h){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="initial-app-launch-and-settings-access-setup" tabindex="-1">Initial App Launch and Settings Access Setup <a class="header-anchor" href="#initial-app-launch-and-settings-access-setup" aria-label="Permalink to &quot;Initial App Launch and Settings Access Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup allows the mobile app to read its main mobile commerce settings when it opens, then store the system access keys needed by later app features.</p><p>When this setup is correct, testers can open the app and reach the login or sign-up screens without the first launch being blocked by missing settings or permission errors.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Create or confirm the Guest role</strong></p><ul><li>Use the search bar at the top of ERPNext.</li><li>Search for <code>Role List</code> and open it.</li><li>Search for a role named <code>Guest</code>.</li><li>If the role already exists, open it and confirm it is available.</li><li>If the role does not exist, click <strong>New</strong>.</li><li>Enter <code>Guest</code> as the role name.</li><li>Save the role.</li></ul></li><li><p><strong>Make sure all users can act as Guest before login</strong></p><ul><li>Use the search bar at the top of ERPNext.</li><li>Search for <code>Role Permission Manager</code> and open it.</li><li>Select <strong>Mobile E-Commerce Settings</strong>.</li><li>Add or confirm a permission row for the role <strong>Guest</strong>.</li><li>Check <strong>Read</strong> for the <strong>Guest</strong> role.</li><li>Save or update the permissions.</li><li>This allows the app to read <strong>Mobile E-Commerce Settings</strong> before the customer logs in.</li></ul></li><li><p><strong>Create a dedicated API User</strong></p><ul><li>Use the search bar at the top of ERPNext.</li><li>Search for <code>User List</code> and open it.</li><li>Click <strong>New</strong>.</li><li>Enter a clear email address for the user, such as <code>api.user@example.com</code>.</li><li>Enter a first name such as <code>API User</code>.</li><li>Make sure the user is <strong>Enabled</strong>.</li><li>Save the user.</li></ul></li><li><p><strong>Give the API User admin permissions</strong></p><ul><li>Stay on the new user&#39;s page.</li><li>Scroll to the <strong>Roles</strong> section.</li><li>Click <strong>Add Row</strong>.</li><li>Select <strong>System Manager</strong>.</li><li>If your company uses role-based restrictions for selling or customer documents, also add the roles normally used to manage customers and sales documents, such as <strong>Sales Manager</strong>.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Generate the API User keys</strong></p><ul><li>Stay on the same user document.</li><li>Scroll to the <strong>Settings</strong> section.</li><li>Find the <strong>API Access</strong> section.</li><li>Click <strong>Generate Keys</strong>.</li><li>ERPNext will show an <strong>API Key</strong> and <strong>API Secret</strong>.</li><li>Copy both values immediately and keep them temporarily in a secure place.</li><li>Do not share these values in chat, email, tickets, or screenshots.</li></ul></li><li><p><strong>Open Mobile E-Commerce Settings</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <code>Mobile E-Commerce Settings</code>.</li><li>Open the document named <strong>Mobile E-Commerce Settings</strong>.</li><li>If ERPNext says the document does not exist, ask the ERPNext administrator to install or enable the mobile commerce custom app/module first.</li></ul></li><li><p><strong>Paste the keys into Mobile E-Commerce Settings</strong></p><ul><li>Scroll to the <strong>API Settings</strong> section.</li><li>Paste the copied <strong>API Key</strong> into the <strong>API Key</strong> field.</li><li>Paste the copied <strong>API Secret</strong> into the <strong>API Secret</strong> field.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Confirm the settings document can be read by the app</strong></p><ul><li>Stay on <strong>Mobile E-Commerce Settings</strong>.</li><li>Confirm the document is saved successfully.</li><li>Confirm the fields in the document are not empty, especially: <ul><li><strong>API Key</strong></li><li><strong>API Secret</strong></li></ul></li><li>Confirm the <strong>Guest</strong> role has <strong>Read</strong> permission for <strong>Mobile E-Commerce Settings</strong> in <strong>Role Permission Manager</strong>.</li></ul></li><li><p><strong>Test the first app launch</strong></p></li></ol><ul><li>Fully close and reopen the mobile app.</li><li>Confirm the app opens normally and reaches the login or sign-up screens.</li><li>The app should not show a permission message or remain blocked on loading.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ol><li><p><strong>If the app shows a permission error during first launch</strong></p><ul><li>This usually means the <strong>API Key</strong> and <strong>API Secret</strong> were not saved in <strong>Mobile E-Commerce Settings</strong>, or they were copied incorrectly.</li><li>Go back to <strong>Mobile E-Commerce Settings &gt; API Settings</strong>.</li><li>Paste the keys again and click <strong>Save</strong>.</li><li>Fully close and reopen the app, then test again.</li></ul></li><li><p><strong>If the app keeps loading and then shows an error dialog</strong></p><ul><li>This usually means the app could not read <strong>Mobile E-Commerce Settings</strong> during first launch.</li><li>Open <strong>Mobile E-Commerce Settings</strong> in ERPNext and confirm the document exists and is saved.</li><li>Ask the ERPNext administrator to verify that the <strong>Guest</strong> role has <strong>Read</strong> permission for this settings document.</li></ul></li><li><p><strong>If the app shows “You do not have permission to access this resource”</strong></p><ul><li>This means the stored keys belong to a user without enough permissions.</li><li>Open <strong>User List</strong>.</li><li>Open the <strong>API User</strong>.</li><li>Add <strong>System Manager</strong> in the <strong>Roles</strong> section.</li><li>Save the user.</li><li>Generate fresh keys if needed, then update <strong>Mobile E-Commerce Settings</strong> again.</li></ul></li><li><p><strong>If the app shows a general network or connection message</strong></p><ul><li>This is usually not caused by the API keys.</li><li>Confirm the phone has internet access.</li><li>Confirm the ERPNext site is online in a browser.</li><li>Try again after the ERPNext site loads normally.</li></ul></li><li><p><strong>If newly generated keys still do not work</strong></p><ul><li>Confirm you copied the full <strong>API Secret</strong> immediately after generating it.</li><li>ERPNext may hide the secret later, so generate a new pair if there is any doubt.</li><li>Update both fields in <strong>Mobile E-Commerce Settings</strong> and click <strong>Save</strong>.</li><li>Fully close and reopen the app before retesting.</li></ul></li></ol>',9)])])}const u=t(n,[["render",r]]);export{d as __pageData,u as default};
